const SITE_CONFIG={label:'Identity Focus',title:'Jeremy Fontenot | Cloud-First IT Professional | Microsoft 365, Entra ID, Intune',tagline:'Cloud-First IT Professional Designing Secure Microsoft 365 Environments',robots:'index, follow'};document.title=SITE_CONFIG.title;const robotsMeta=document.querySelector('meta[name="robots"]');if(robotsMeta){robotsMeta.setAttribute('content',SITE_CONFIG.robots);}
const heroTagline=document.querySelector('.hero-tagline');if(heroTagline){heroTagline.textContent=SITE_CONFIG.tagline;}
const prefersReducedMotion=window.matchMedia('(prefers-reduced-motion: reduce)').matches;const smoothBehavior=prefersReducedMotion?'auto':'smooth';const heroVisual=document.querySelector('.hero-visual');const heroMainLogo=document.querySelector('.hero-main-logo');const supportsHoverPointer=window.matchMedia('(hover: hover) and (pointer: fine)').matches;if(heroVisual&&heroMainLogo&&!prefersReducedMotion&&supportsHoverPointer){const maxTilt=11;heroVisual.addEventListener('pointermove',(event)=>{const rect=heroVisual.getBoundingClientRect();const relativeX=(event.clientX-rect.left)/rect.width;const relativeY=(event.clientY-rect.top)/rect.height;const tiltY=(relativeX-0.5)*(maxTilt*2);const tiltX=(0.5-relativeY)*(maxTilt*2);heroMainLogo.style.setProperty('--tilt-x',`${tiltX.toFixed(2)}deg`);heroMainLogo.style.setProperty('--tilt-y',`${tiltY.toFixed(2)}deg`);});const resetTilt=()=>{heroMainLogo.style.setProperty('--tilt-x','0deg');heroMainLogo.style.setProperty('--tilt-y','0deg');};heroVisual.addEventListener('pointerleave',resetTilt);heroVisual.addEventListener('pointercancel',resetTilt);}
const heroLiveStats=document.querySelectorAll('.hero-live-stat-value[data-target]');if(heroLiveStats.length>0){const animateStatValue=(node)=>{const target=Number.parseInt(node.dataset.target||'0',10);if(!Number.isFinite(target)||target<=0){return;}
const suffix=node.textContent.trim().replace(/[\d\s]/g,'')||'+';if(prefersReducedMotion){node.textContent=`${target}${suffix}`;return;}
const duration=1100;const startTime=performance.now();const updateFrame=(now)=>{const progress=Math.min((now-startTime)/duration,1);const easedProgress=1-Math.pow(1-progress,3);const value=Math.max(1,Math.round(target*easedProgress));node.textContent=`${value}${suffix}`;if(progress<1){window.requestAnimationFrame(updateFrame);}};window.requestAnimationFrame(updateFrame);};const triggerStats=()=>{heroLiveStats.forEach((node)=>animateStatValue(node));};const heroSection=document.getElementById('home');if(heroSection&&'IntersectionObserver'in window&&!prefersReducedMotion){const heroObserver=new IntersectionObserver((entries,observer)=>{entries.forEach((entry)=>{if(entry.isIntersecting){triggerStats();observer.disconnect();}});},{threshold:0.42});heroObserver.observe(heroSection);}else{triggerStats();}}
document.querySelectorAll('a[href^="#"]').forEach((anchor)=>{anchor.addEventListener('click',function onAnchorClick(e){const targetSelector=this.getAttribute('href');if(!targetSelector||targetSelector==='#'){return;}
const target=document.querySelector(targetSelector);if(!target){return;}
e.preventDefault();target.scrollIntoView({behavior:smoothBehavior,block:'start'});history.replaceState(null,'',targetSelector);});});const navToggle=document.querySelector('.nav-toggle');const navLinks=document.querySelector('.nav-links');if(navToggle&&navLinks){navToggle.addEventListener('click',()=>{const isOpen=navLinks.classList.toggle('open');navToggle.setAttribute('aria-expanded',isOpen?'true':'false');});navLinks.querySelectorAll('a').forEach((link)=>{link.addEventListener('click',()=>{navLinks.classList.remove('open');navToggle.setAttribute('aria-expanded','false');});});}
const contactForm=document.getElementById('contact-form');const formStatus=document.getElementById('form-status');const certFilterButtons=document.querySelectorAll('.cert-filter-btn[data-filter]');const certItems=document.querySelectorAll('.cert-grid .cert-item');if(certItems.length>0){certItems.forEach((item)=>{if(!item.querySelector('.cert-verified-badge')){const verifiedBadge=document.createElement('span');verifiedBadge.className='cert-verified-badge';verifiedBadge.textContent='Verified';item.appendChild(verifiedBadge);}
const authority=item.dataset.certAuthority||item.querySelector('.cert-provider')?.textContent?.trim()||'Issuing Authority';const year=item.dataset.certYear||'See credential';if(!item.querySelector('.cert-hover-meta')){const hoverMeta=document.createElement('div');hoverMeta.className='cert-hover-meta';hoverMeta.innerHTML=`
                <span class="cert-hover-label">Issuing Authority</span>
                <span class="cert-hover-value">${authority}</span>
                <span class="cert-hover-label">Year</span>
                <span class="cert-hover-value">${year}</span>
            `;item.appendChild(hoverMeta);}});}
if(certFilterButtons.length>0&&certItems.length>0){const setCertFilter=(filter)=>{certFilterButtons.forEach((button)=>{const isActive=button.dataset.filter===filter;button.classList.toggle('is-active',isActive);button.setAttribute('aria-pressed',isActive?'true':'false');});certItems.forEach((item)=>{const categories=(item.dataset.certCategories||'').toLowerCase().split(',').map((entry)=>entry.trim()).filter(Boolean);const shouldShow=filter==='all'||categories.includes(filter);item.classList.toggle('is-hidden',!shouldShow);});};certFilterButtons.forEach((button)=>{button.addEventListener('click',()=>{const selected=button.dataset.filter||'all';setCertFilter(selected);});});setCertFilter('all');}
if(contactForm&&formStatus){contactForm.addEventListener('submit',(event)=>{event.preventDefault();const nameField=document.getElementById('name');const emailField=document.getElementById('email');const messageField=document.getElementById('message');const name=nameField?nameField.value.trim():'';const email=emailField?emailField.value.trim():'';const message=messageField?messageField.value.trim():'';const emailPattern=/^[^\s@]+@[^\s@]+\.[^\s@]{2,}$/;if(name.length<2){formStatus.textContent='Please enter a valid name (at least 2 characters).';formStatus.classList.add('is-error');nameField?.focus();return;}
if(!emailPattern.test(email)){formStatus.textContent='Please enter a valid email address.';formStatus.classList.add('is-error');emailField?.focus();return;}
if(message.length<20){formStatus.textContent='Please include more detail in your message (minimum 20 characters).';formStatus.classList.add('is-error');messageField?.focus();return;}
const subject=encodeURIComponent(`Portfolio inquiry from ${name}`);const body=encodeURIComponent(`Name: ${name}\nEmail: ${email}\n\nMessage:\n${message}`);window.location.href=`mailto:jeremy@jeremyfontenot.online?subject=${subject}&body=${body}`;formStatus.textContent='Thank you. Your email client should open with your message pre-filled.';formStatus.classList.remove('is-error');contactForm.reset();});}
window.addEventListener('scroll',()=>{const nav=document.querySelector('nav');if(nav){nav.style.background=window.scrollY>50?'rgba(15, 23, 42, 0.98)':'rgba(11, 16, 32, 0.84)';}},{passive:true});